/* ═══════════════════════════════════════════════════════════════
   LOGIC.JS  —  Stappenteller  v4.0
   Cockpit Framework — swappable logica

   KERNWIJZIGING v4.0 — ACCUMULATIEMETHODE:
   ─────────────────────────────────────────
   Vorige versies berekenden afstand en snelheid per GPS-fix.
   Probleem: bij fix-interval van 1-3s en mediaan-smoothing is
   de per-fix afstand te klein en de snelheid onbetrouwbaar.

   Oplossing: accumuleer ruwe afstanden over meerdere fixes totdat
   een minimumdrempel (ACCUM_DIST_M = 5m) bereikt is. Dan pas
   snelheid berekenen over dat hele venster. Dit geeft een stabiele
   snelheidsmeting onafhankelijk van fix-frequentie.

   FILTERKETEN:
     1. Accuratesse > 50m          → weggooien
     2. Fix-afstand > 150m         → teleport, weggooien
     3. Accumuleer fixes tot ≥ 5m
     4. Snelheid over accumulatievenster:
        < 0.37 m/s  → stilstand, reset accumulatie
        > 1.944 m/s → te snel, reset accumulatie
        Anders      → stappen berekenen en tellen
   ═══════════════════════════════════════════════════════════════ */

'use strict';

/* ── CONSTANTEN ─────────────────────────────────────────────────── */
const STEP_STORAGE_KEY    = 'cockpit_dag_v4';
const SESSION_STORAGE_KEY = 'cockpit_sessie_v4';
const STEPLEN_KEY         = 'cockpit_staplengte_v4';

const DEFAULT_STEP_M  = 0.67;   /* standaard staplengte in meter              */
const STRIDE_FACTOR   = 2;      /* 1 pas = 2 stappen (links + rechts)         */

/* Accumulatie-drempel: ophopen tot 5m vóór evaluatie.
   Reden: bij acc=4m en fix-jitter is een enkele fix van 1-3m
   te onbetrouwbaar om snelheid op te meten.
   5m = typisch 3-6 fixes = 6-12 seconden wandelen.            */
const ACCUM_DIST_M    = 5.0;

const MAX_FIX_DIST_M  = 150.0;  /* max afstand per fix — teleport-filter      */
const MIN_SPEED_MS    = 0.37;   /* min wandelsnelheid m/s (~1.3 km/u)         */
const MAX_SPEED_MS    = 1.944;  /* max wandelsnelheid m/s (7 km/u)            */
const ACCURACY_LIMIT  = 50;     /* max GPS-onnauwkeurigheid in meter           */
const BLACKBOX_MS     = 3000;   /* zwarte doos interval                       */
const EARTH_R         = 6371000;/* aardstraal meter                           */

/* ── STAAT ──────────────────────────────────────────────────────── */
let _stepLen    = DEFAULT_STEP_M;

/* Accumulatie-buffer: oplopende afstand + tijdvenster */
let _accumDist  = 0;     /* opgelopen afstand in meters                       */
let _accumStart = null;  /* timestamp begin van huidig accumulatievenster      */

/* GPS referentie voor haversine */
let _prevLat    = null;
let _prevLng    = null;
let _lastSaveTs = 0;

/* Sessie-state */
const S = {
  active:       false,
  paused:       false,
  steps:        0,
  meters:       0,
  startTs:      null,
  pausedMs:     0,
  pauseStartTs: null,
  fixCount:     0,
  speedMs:      null,   /* laatste berekende snelheid voor UI                  */
  restored:     false
};

let dayData = { date: _todayStr(), steps: 0, meters: 0 };

/* ── HULPFUNCTIES ───────────────────────────────────────────────── */
function _todayStr() {
  return new Date().toLocaleDateString('nl-BE');
}

function _haversine(lat1, lng1, lat2, lng2) {
  const dLat = (lat2-lat1)*Math.PI/180;
  const dLng = (lng2-lng1)*Math.PI/180;
  const a = Math.sin(dLat/2)**2
          + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLng/2)**2;
  return EARTH_R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function _fmtDuration(ms) {
  const s=Math.floor(ms/1000), h=Math.floor(s/3600), m=Math.floor((s%3600)/60), sc=s%60;
  const p=n=>String(n).padStart(2,'0');
  return h>0 ? p(h)+':'+p(m)+':'+p(sc) : p(m)+':'+p(sc);
}

function _fmtDist(m) {
  return m>=1000 ? (m/1000).toFixed(2)+' km' : Math.round(m)+' m';
}

function _activeDuration() {
  if (!S.startTs) return 0;
  const totalMs = Date.now()-S.startTs;
  const pauseMs = S.pausedMs+(S.paused&&S.pauseStartTs?Date.now()-S.pauseStartTs:0);
  return Math.max(0, totalMs-pauseMs);
}

/* Reset accumulatie — bij start, pauze, te snel/langzaam */
function _resetAccum(lat, lng) {
  _accumDist  = 0;
  _accumStart = Date.now();
  _prevLat    = lat;
  _prevLng    = lng;
}

/* ── LOCALSTORAGE ───────────────────────────────────────────────── */
function _loadDay() {
  try {
    const raw=localStorage.getItem(STEP_STORAGE_KEY);
    if(raw){const p=JSON.parse(raw);if(p&&p.date===_todayStr()){dayData=p;return;}}
  } catch(e){}
  dayData={date:_todayStr(),steps:0,meters:0};
}

function _saveDay() {
  try{localStorage.setItem(STEP_STORAGE_KEY,JSON.stringify(dayData));}catch(e){}
}

function _saveBlackBox() {
  if(!S.active) return;
  const now=Date.now();
  if(now-_lastSaveTs<BLACKBOX_MS) return;
  _lastSaveTs=now;
  try{
    localStorage.setItem(SESSION_STORAGE_KEY,JSON.stringify({
      steps:S.steps,meters:S.meters,startTs:S.startTs,
      pausedMs:S.pausedMs,savedAt:now,
      prevLat:_prevLat,prevLng:_prevLng,
      daySteps:dayData.steps,dayMeters:dayData.meters,dayDate:dayData.date
    }));
  }catch(e){}
}

function _clearBlackBox() {
  try{localStorage.removeItem(SESSION_STORAGE_KEY);}catch(e){}
}

function _restoreBlackBox() {
  try{
    const raw=localStorage.getItem(SESSION_STORAGE_KEY);
    if(!raw) return false;
    const snap=JSON.parse(raw);
    if(!snap||!snap.savedAt||Date.now()-snap.savedAt>86400000){_clearBlackBox();return false;}
    S.steps=snap.steps||0; S.meters=snap.meters||0;
    S.startTs=snap.startTs||Date.now(); S.pausedMs=snap.pausedMs||0;
    S.active=true; S.paused=true; S.restored=true;
    _prevLat=snap.prevLat||null; _prevLng=snap.prevLng||null;
    if(snap.dayDate===_todayStr()){
      dayData.steps=snap.daySteps||dayData.steps;
      dayData.meters=snap.dayMeters||dayData.meters;
    }
    console.log('[BlackBox] Hersteld:',S.steps,'stappen');
    return true;
  }catch(e){_clearBlackBox();return false;}
}

/* ── GPS_BUS CALLBACK ───────────────────────────────────────────── */
GPS_BUS.onFix((lat, lng, accuracy, raw) => {
  S.fixCount++;

  /* SW-gecachte fix — geen stappen */
  if (raw===null) { _updateUI(); return; }

  /* Filter 1: slechte accuratesse */
  if (accuracy > ACCURACY_LIMIT) { _updateUI(); return; }

  /* Positie altijd bijhouden buiten sessie als referentie */
  if (!S.active || S.paused) {
    _prevLat=lat; _prevLng=lng;
    _updateUI(); return;
  }

  /* Eerste fix na start */
  if (_prevLat===null) {
    _resetAccum(lat, lng);
    _updateUI(); return;
  }

  /* Afstand tot vorige fix */
  const fixDist = _haversine(_prevLat, _prevLng, lat, lng);

  /* Filter 2: teleport-filter per fix */
  if (fixDist > MAX_FIX_DIST_M) {
    console.log(`[GPS] Teleport ${fixDist.toFixed(0)}m genegeerd`);
    _resetAccum(lat, lng);
    _updateUI(); return;
  }

  /* Accumuleer afstand */
  _accumDist += fixDist;
  _prevLat=lat; _prevLng=lng;

  /* Nog niet genoeg opgehoopt — wacht op meer fixes */
  if (_accumDist < ACCUM_DIST_M) {
    _updateUI(); return;
  }

  /* Genoeg afstand — bereken snelheid over het accumulatievenster */
  const elapsedSec = (Date.now() - _accumStart) / 1000;
  const speedMs    = elapsedSec > 0 ? _accumDist / elapsedSec : 0;
  S.speedMs        = speedMs;

  /* Filter 3: snelheidsvenster */
  if (speedMs < MIN_SPEED_MS) {
    /* Te langzaam — stilstand of zitten. Reset en begin opnieuw. */
    console.log(`[Filter] Te langzaam: ${(speedMs*3.6).toFixed(1)}km/u`);
    _resetAccum(lat, lng);
    _updateUI(); return;
  }

  if (speedMs > MAX_SPEED_MS) {
    /* Te snel — fietser, auto of GPS-sprong. Reset en begin opnieuw. */
    console.log(`[Filter] Te snel: ${(speedMs*3.6).toFixed(1)}km/u`);
    _resetAccum(lat, lng);
    _updateUI(); return;
  }

  /* ✓ Wandeltempo bevestigd — stappen berekenen */
  const strideLenM = _stepLen * STRIDE_FACTOR;
  const newPaces   = Math.round(_accumDist / strideLenM);
  const newSteps   = newPaces * STRIDE_FACTOR;

  if (newSteps > 0) {
    S.steps        += newSteps;
    S.meters       += _accumDist;
    dayData.steps  += newSteps;
    dayData.meters += _accumDist;
    _saveDay();
    _saveBlackBox();
    console.log(`[Stap] +${newSteps} stappen | ${_accumDist.toFixed(1)}m over ${elapsedSec.toFixed(1)}s | ${(speedMs*3.6).toFixed(1)}km/u | totaal=${S.steps}`);
  }

  /* Reset accumulatie voor volgend venster */
  _resetAccum(lat, lng);
  _updateUI();
});

GPS_BUS.onError((_code, msg) => {
  const el=document.getElementById('step-gps-status');
  if(el){el.innerText=msg;el.style.color='var(--danger-red)';}
});

/* ── KNOPPEN ────────────────────────────────────────────────────── */
async function toggleSession() {
  if (!S.active) {
    /* START */
    await _initAudio();
    _startAudioLoop();
    if (!S.restored) {
      S.steps=0; S.meters=0; S.startTs=Date.now(); S.pausedMs=0;
    }
    S.active=true; S.paused=false; S.restored=false;
    if (APP.gps.hasfix) _resetAccum(APP.gps.lat, APP.gps.lng);
    else { _prevLat=null; _prevLng=null; _accumDist=0; _accumStart=Date.now(); }
    console.log('[Toggle] START');

  } else if (!S.paused) {
    /* PAUZE */
    S.paused=true; S.pauseStartTs=Date.now();
    console.log('[Toggle] PAUZE');

  } else {
    /* HERVAT */
    S.pausedMs  += Date.now()-(S.pauseStartTs||Date.now());
    S.paused     = false; S.pauseStartTs=null;
    if (APP.gps.hasfix) _resetAccum(APP.gps.lat, APP.gps.lng);
    console.log('[Toggle] HERVAT');
  }
  _updateUI();
}

function stopAndReset() {
  _stopAudioLoop();
  _clearBlackBox();
  S.active=false; S.paused=false; S.steps=0; S.meters=0;
  S.startTs=null; S.pausedMs=0; S.pauseStartTs=null;
  S.speedMs=null; S.restored=false; S.fixCount=0;
  _accumDist=0; _accumStart=null;
  _prevLat=APP.gps.lat; _prevLng=APP.gps.lng;
  console.log('[Toggle] STOP+RESET');
  _updateUI();
}

function resetDay() {
  if(!confirm('Dagelijkse teller resetten naar nul?')) return;
  dayData={date:_todayStr(),steps:0,meters:0};
  _saveDay(); _updateUI();
}

/* ── AUDIO KEEPALIVE ────────────────────────────────────────────── */
const _SILENT_WAV_B64 = '';
const _SILENT_WAV_URL = 'data:audio/wav;base64,'+_SILENT_WAV_B64;

let _audioCtx=null, _audioSource=null, _audioActive=false;

async function _initAudio() {
  if (_audioCtx) return;
  try {
    _audioCtx=new(window.AudioContext||window.webkitAudioContext)();
    const resp=await fetch(_SILENT_WAV_URL);
    const buf=await resp.arrayBuffer();
    _audioCtx._silentBuf=await _audioCtx.decodeAudioData(buf);
  } catch(e){console.warn('[Audio]',e.message);_audioCtx=null;}
}

function _startAudioLoop() {
  if (!_audioCtx||!_audioCtx._silentBuf||_audioActive) return;
  try {
    _audioSource=_audioCtx.createBufferSource();
    _audioSource.buffer=_audioCtx._silentBuf;
    _audioSource.loop=true;
    _audioSource.connect(_audioCtx.destination);
    _audioSource.start(0);
    _audioActive=true;
    if ('mediaSession' in navigator) {
      navigator.mediaSession.metadata=new MediaMetadata({title:'GPS Tracking',artist:'Stappenteller',album:'Achtergrond'});
      navigator.mediaSession.setActionHandler('play', ()=>{if(_audioCtx.state==='suspended')_audioCtx.resume();});
      navigator.mediaSession.setActionHandler('pause',()=>{setTimeout(()=>{if(_audioCtx.state==='suspended')_audioCtx.resume();},500);});
      navigator.mediaSession.playbackState='playing';
    }
  } catch(e){_audioActive=false;}
}

function _stopAudioLoop() {
  if (!_audioActive||!_audioSource) return;
  try{_audioSource.stop();_audioSource.disconnect();}catch(e){}
  _audioSource=null;_audioActive=false;
  if('mediaSession' in navigator) navigator.mediaSession.playbackState='none';
}

/* ── CONFIG ─────────────────────────────────────────────────────── */
function saveStepLen() {
  const inp=document.getElementById('cfg-step-len-input'); if(!inp) return;
  const v=parseFloat(inp.value);
  if(isNaN(v)||v<0.30||v>1.20){alert('Staplengte moet tussen 0.30m en 1.20m liggen.');return;}
  _stepLen=v;
  try{localStorage.setItem(STEPLEN_KEY,String(_stepLen));}catch(e){}
  _updateUI();
  const s=document.getElementById('cfg-step-status');
  if(s){s.innerText='Opgeslagen: '+_stepLen.toFixed(2)+'m  (pas: '+(_stepLen*2).toFixed(2)+'m)';s.className='cfg-status ok';s.style.display='block';}
}

/* ── UI UPDATE ──────────────────────────────────────────────────── */
function _updateUI() {
  const now=new Date();
  const pad=n=>String(n).padStart(2,'0');

  const utcEl=document.getElementById('utc-time');
  if(utcEl) utcEl.innerText=[now.getUTCHours(),now.getUTCMinutes(),now.getUTCSeconds()].map(pad).join(':');
  const locEl=document.getElementById('local-time');
  if(locEl) locEl.innerText=now.toLocaleTimeString('nl-BE');
  const dateEl=document.getElementById('date-display');
  if(dateEl) dateEl.innerText=now.toLocaleDateString('nl-BE',{weekday:'long',day:'numeric',month:'long',year:'numeric'});

  const ssEl=document.getElementById('session-steps');
  if(ssEl) ssEl.innerText=S.steps.toLocaleString('nl-BE');
  const sdEl=document.getElementById('session-dist');
  if(sdEl) sdEl.innerText=_fmtDist(S.meters);
  const stEl=document.getElementById('session-duration');
  if(stEl) stEl.innerText=S.startTs?_fmtDuration(_activeDuration()):'--:--';
  const spEl=document.getElementById('session-speed');
  if(spEl) spEl.innerText=(S.active&&!S.paused&&S.speedMs!==null)?(S.speedMs*3.6).toFixed(1)+' km/u':'--';

  /* Accumulatie voortgang — toont hoeveel van de 5m al opgehoopt is */
  const accEl=document.getElementById('accum-bar');
  if(accEl){
    const pct=Math.min(100,Math.round(_accumDist/ACCUM_DIST_M*100));
    accEl.style.width=pct+'%';
  }
  const accTxt=document.getElementById('accum-txt');
  if(accTxt) accTxt.innerText=S.active&&!S.paused?_accumDist.toFixed(1)+'m / '+ACCUM_DIST_M+'m':'';

  /* GPS status */
  const gpsEl=document.getElementById('step-gps-status');
  if(gpsEl){
    if(!APP.gps.hasfix){
      gpsEl.innerText='Wachten op GPS fix...';gpsEl.style.color='var(--warn-orange)';
    } else if(S.active&&!S.paused&&S.speedMs!==null){
      const kmh=(S.speedMs*3.6).toFixed(1);
      const staat=S.speedMs<MIN_SPEED_MS?'⏸ STILSTAND':S.speedMs>MAX_SPEED_MS?'🚫 TE SNEL':'🚶 WANDELEN';
      const kleur=S.speedMs<MIN_SPEED_MS?'var(--warn-orange)':S.speedMs>MAX_SPEED_MS?'var(--danger-red)':'var(--glow-green)';
      gpsEl.innerText=staat+'  '+kmh+' km/u  ±'+Math.round(APP.gps.accuracy)+'m';
      gpsEl.style.color=kleur;
    } else {
      gpsEl.innerText='GPS ±'+Math.round(APP.gps.accuracy)+'m  ('+S.fixCount+' fixes)';
      gpsEl.style.color='var(--glow-green)';
    }
  }

  const audioEl=document.getElementById('audio-status');
  if(audioEl){audioEl.innerText=_audioActive?'AUDIO: AAN':'--';audioEl.style.color=_audioActive?'var(--glow-green)':'#444';}

  const dsEl=document.getElementById('day-steps'); if(dsEl) dsEl.innerText=dayData.steps.toLocaleString('nl-BE');
  const ddEl=document.getElementById('day-dist');  if(ddEl) ddEl.innerText=_fmtDist(dayData.meters);
  const pct=Math.min(100,Math.round(dayData.steps/100));
  const goalEl=document.getElementById('day-goal-pct');
  if(goalEl){goalEl.innerText=pct+'%';goalEl.style.color=pct>=100?'var(--glow-green)':pct>=50?'var(--accent-gold)':'var(--warn-orange)';}
  const barEl=document.getElementById('day-goal-bar'); if(barEl) barEl.style.width=pct+'%';

  /* Wisselknop */
  const btnEl=document.getElementById('session-toggle-btn');
  if(btnEl){
    if(!S.active){
      btnEl.innerText='▶  START METING';
      btnEl.style.background='rgba(0,255,153,0.12)';btnEl.style.borderColor='var(--glow-green)';btnEl.style.color='var(--glow-green)';
    }else if(!S.paused){
      btnEl.innerText='⏸  PAUZE';
      btnEl.style.background='rgba(255,153,0,0.12)';btnEl.style.borderColor='var(--warn-orange)';btnEl.style.color='var(--warn-orange)';
    }else{
      btnEl.innerText='▶  HERVAT';
      btnEl.style.background='rgba(68,136,255,0.12)';btnEl.style.borderColor='var(--home-blue)';btnEl.style.color='var(--home-blue)';
    }
  }

  const restEl=document.getElementById('restored-indicator');
  if(restEl) restEl.style.display=S.restored?'block':'none';
  const slEl=document.getElementById('cfg-step-len-display');
  if(slEl) slEl.innerText=_stepLen.toFixed(2)+'m  (pas: '+(_stepLen*2).toFixed(2)+'m)';
  const wlEl=document.getElementById('cfg-wake-status');
  if(wlEl){const ind=document.getElementById('wake-lock-indicator');wlEl.innerText=(ind&&ind.style.opacity==='1')?'Actief':'Niet actief';}
}

/* ── TAB CHANGE ─────────────────────────────────────────────────── */
APP.onTabChange=function(viewId){
  if(viewId==='config'){const inp=document.getElementById('cfg-step-len-input');if(inp)inp.value=_stepLen.toFixed(2);}
};

/* ── LOGIC_INIT ─────────────────────────────────────────────────── */
function LOGIC_INIT() {
  _loadDay();
  try{const s=localStorage.getItem(STEPLEN_KEY);if(s){const v=parseFloat(s);if(v>=0.30&&v<=1.20)_stepLen=v;}}catch(e){}
  const restored=_restoreBlackBox();
  if(restored){
    const restEl=document.getElementById('restored-indicator');
    if(restEl){restEl.style.display='block';restEl.innerText='Sessie hersteld ('+S.steps+' stappen bewaard) — druk HERVAT om door te gaan';}
  }
  _updateUI();
  setInterval(_updateUI,1000);
  console.log('[Stappenteller v4] Staplengte:',_stepLen+'m | Paslengte:',(_stepLen*2).toFixed(2)+'m | Accumulatiedrempel:',ACCUM_DIST_M+'m');
}
